INSERT INTO areas (name, description, main_image) VALUES
('Forgotten Crossroads', 'A bustling hub of travel for the kingdom of Hallownest, now fallen into decay and infested with husks. It connects many of the higher paths of the world.', 'forgottenCrossroads.jpg'),
('Greenpath', 'A lush, verdant labyrinth of moss and vegetation. It is home to the Mosskin and is protected by the mysterious warrior, Hornet.', 'greenpath.jpg'),
('City of Tears', 'The capital of Hallownest, where it eternally rains. Built into a massive cavern, it remains a monument to the kingdoms former glory.', 'cityofTears.jpg'),
('Crystal Peak', 'A glittering mine filled with dangerous crystals and industrial machinery. The light here is beautiful but deadly to those unprepared.', 'crystalPeak.jpg'),
('Deepnest', 'A dark, claustrophobic network of tunnels and spider webs. It is home to the most terrifying creatures in Hallownest and is avoided by most.', 'deepnest.jpg');